from typing import List

class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        # Find all indices where a appears in s
        a_indices = [i for i in range(len(s) - len(a) + 1) if s[i:i+len(a)] == a]
        # Find all indices where b appears in s
        b_indices = [i for i in range(len(s) - len(b) + 1) if s[i:i+len(b)] == b]

        # For each index in a_indices, check if there's a b index within k distance
        result = []
        for i in a_indices:
            # Use binary search to find if any b index is within [i - k, i + k]
            left, right = 0, len(b_indices)
            while left < right:
                mid = (left + right) // 2
                if b_indices[mid] < i - k:
                    left = mid + 1
                else:
                    right = mid
            if left < len(b_indices) and b_indices[left] - i <= k:
                result.append(i)

        return result
